var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"대답이 없으셔서 걱정했습니다. 아직 방에 남아 계셨군요.","JPN":"返事がないので心配しました。まだお部屋にいらっしゃいましたか。","ENG":"You didn't answer, so I was a bit worried. Still in your room, I see.","TWN":"你沒有回應，我很擔心。原來你還在房間裡啊。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"쓰지 않던 글까지 쓰시고, 무슨 일이십니까?","JPN":"珍しく書き物などされて、どうなさったんですか？","ENG":"Even writing something? That's not like you. Is something wrong?","TWN":"連不常寫的信都寫了，發生什麼事了？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"현 전황을 분석하며 유용할 법한 전술을 추리고 있었습니다.","JPN":"現在の戦況を分析し、使えそうな戦術を選んでいるところです。","ENG":"Just reviewing the current situation and jotting down some useful tactics.","TWN":"正在分析當前戰況，並篩選出可能有用的戰術。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"간략하게 적은 병서에 불과하지만, 알렌이라면 이조차 유의미하게 사용해주겠죠.","JPN":"簡単に書き込んだ兵書にすぎませんが、アレンならこれを有効に活用してくれるでしょう。","ENG":"It's a brief draft of strategies, but if it's Allen, even this should come in handy.","TWN":"雖然只是簡略的兵書，但如果是艾倫的話，即使這樣也會有意義地使用吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"괜찮을까요? 백작님께서 워낙 스파르타식으로 가르치신 탓에.","JPN":"大丈夫なんですか？　伯爵からスパルタ式に叩き込まれたせいで。","ENG":"You think so? You trained him so strictly,","TWN":"沒問題嗎？伯爵大人的教導太過嚴厲，"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"아직도 단장님께서는 병서만 보시면 낯빛이 창백해지시던데요.","JPN":"いまだに団長は兵書を見るだけで顔色が悪くなるんです。","ENG":"that he still turns pale at the sight of a strategy manual.","TWN":"團長一看到兵書，臉色還是會變得蒼白呢。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전쟁에 전술만큼이나 중요한 것은 없습니다. 그리고 스파르타가 아니라 애정이에요.","JPN":"戦争で戦術学ほど重要なものはありません。それに、あれはスパルタではなく愛情ですよ。","ENG":"Nothing's more important in war than sound tactics. And it wasn't strictness, it was love.","TWN":"在戰爭中，沒有什麼比戰術學更重要的了。而且，這不是嚴厲，而是愛。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"루지에 경도 저처럼 헌신적인 아내가 생겨야 이 기분을 이해하실 텐데… 안타깝군요.","JPN":"ルージ卿も私のように献身的な妻を持てばこの気持ちがわかるはずですが……残念です。","ENG":"Sir Rougié needs a devoted wife like me to truly understand... A shame, really.","TWN":"你也需要有像我這樣的賢妻才能理解這種心情吧……真是遺憾呢。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"혹시 죽을병에라도 걸리셨습니까?","JPN":"不治の病にでも罹られたんですか？","ENG":"Are you dying or something?","TWN":"難道得了什麼絕症嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 사실 이건 병서가 아니라 유서였답니다.","JPN":"ええ。実はこれは兵書ではなく、遺書なのです。","ENG":"Yes, in fact. This isn't a strategy book. It's my will.","TWN":"是的，其實這不是兵書，而是遺書。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"마침 루지에 경을 해고시켜달라고 적는 참이었지요.","JPN":"ちょうどルージ卿の解雇を願う文面をしたためているところでした。","ENG":"I was just writing a request to have Sir Rougié dismissed.","TWN":"我正在寫信請求解雇路吉爾卿呢。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"마지막까지 예술로 가시는군요, 참.","JPN":"去り際まで見事ですね。はあ。","ENG":"Even your final moments are dramatic.","TWN":"最後還是選擇了藝術之路啊，真是的。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 농담이랍니다.","JPN":"ふふ、冗談です。","ENG":"Haha, I'm joking.","TWN":"呵呵，我開玩笑的喔。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무엇보다 생을 마감한다면 사랑하는 이가 준비해준 자리에서 눈을 감을 생각이라서요.","JPN":"なにより一生を終える時には、愛する人が用意してくれた場所で眠るつもりなのです。","ENG":"If I really were dying, I'd want to peacefully go somewhere my beloved prepared for me.","TWN":"最重要的是，如果要結束生命，我想在愛人為我準備的地方閉上眼睛。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"이번 탄신일에 단장님께 묘비라도 선물해달라고 하시게요?","JPN":"今度のお誕生日に、団長に墓石でもプレゼントしてもらうおつもりですか？","ENG":"You're planning to ask the captain for a gravestone on your birthday?","TWN":"這次生日要不要送團長一塊墓碑呢？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그것도 퍽 로맨틱하겠군요. 진지하게 고려해보겠습니다.","JPN":"それもロマンチックですね。真剣に考えてみます。","ENG":"Isn't that a romantic gesture? I'll think about it.","TWN":"那也挺浪漫的。我會認真考慮的。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"그건 상관없는데, 제 아이디어였다고는 말하지 말아주십쇼.","JPN":"それはいいですけど、私のアイデアだなんて言わないでくださいよ。","ENG":"Fine, just don't tell anyone it was my idea.","TWN":"這個不是問題，但請不要說是我的主意。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"자, 장난은 이쯤하고 그만 본론으로 넘어가지요.","JPN":"さて、冗談はここまでにして本題に入りましょうか。","ENG":"E-enough joking. Let's get back to business.","TWN":"好了，玩笑到此為止，我們還是進入正題吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"부탁했던 건 어떻게 됐나요?","JPN":"頼んでいたものはどうなりました？","ENG":"How did the preparations go?","TWN":"我拜託你的事情怎麼樣了？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"백작령을 지킬 병사들을 제외한 원정대의 편성을 끝마쳤습니다.","JPN":"伯爵領を守る兵士を除いて遠征隊を編成しました。","ENG":"The expedition is assembled, minus the troops staying to defend the County.","TWN":"除了保護伯爵領地的士兵外，遠征隊的編制已經完成。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"마지막 남은 처녀자리의 무구가 완성되면 마침내 열두 무구의 선별이 끝나는군요.","JPN":"残る乙女座の武具が完成すれば、12武具の選別は終わりです。","ENG":"Once the remaining Virgo Armament is complete, we'll have all twelve chosen.","TWN":"最後一件處女座的聖遺物完成後，十二聖遺物的選拔終於結束了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"제국 신민들이 염원하던 계승식도 무사히 거행될 것입니다.","JPN":"帝国の臣民が待ち望んでいた継承式も無事行われるでしょう。","ENG":"The succession ceremony the Empire's people have long awaited can finally begin.","TWN":"帝國臣民們所期盼的繼承儀式也將順利舉行。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……예. 그렇겠죠.","JPN":"……ええ、そうでしょうね。","ENG":"...Yes. It can.","TWN":"是的，沒錯。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제가 곧 갈 터이니, 루지에 경은 백작령에 남을 기사들을 인솔해주시길 바랍니다.","JPN":"すぐに向かいますので、ルージ卿は伯爵領に残る騎士たちをお願いします。","ENG":"I'll be leaving soon. Sir Rougié, I'm entrusting the remaining knights to you.","TWN":"我馬上就去，請路吉爾率領留在伯爵領地的騎士們。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"예. 받들겠습니다.","JPN":"はい。承知いたしました。","ENG":"Understood.","TWN":"是。我會遵從的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"루지에 경. 잠시 괜찮을까요?","JPN":"ルージ卿。少しいいでしょうか？","ENG":"Sir Rougié, one more thing.","TWN":"路吉爾卿。打擾一下？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};